from django.utils.module_loading import import_string

class MasterKeyManager:
    def __init__(self):
        self.master_key = MASTER_KEY
        self.key_provider = self._get_provider()

    def _get_provider(self):
        provider_class_path = PROVIDER_REGISTRY.get('fernet')
        if not provider_class_path:
            raise ValueError("Fernet provider not found in registry.")
        provider_class = import_string(provider_class_path)
        return provider_class(self.master_key)

class EncryptionManager:
    def __init__(self, master_key_manager):
        self.master_key_manager = master_key_manager

    def encrypt(self, input_data):
        fernet = self.master_key_manager.key_provider
        return fernet.encrypt(input_data)

    def decrypt(self, encrypted_data):
        fernet = self.master_key_manager.key_provider
        return fernet.decrypt(encrypted_data)

class DecryptionManager:
    def __init__(self, master_key_manager):
        self.master_key_manager = master_key_manager

