from django.db import models
from .managers import MasterKeyManager, EncryptionManager, DecryptionManager

PROVIDER_REGISTRY = {
    'fernet': 'path.to.FernetProvider',
}

MASTER_KEY = b'master_key_here'

class TOTPDevice(models.Model):
    key = models.BinaryField()

    @classmethod
    def get_master_key_manager(cls):
        return MasterKeyManager()

    @classmethod
    def get_encryption_manager(cls):
        return EncryptionManager(cls.get_master_key_manager())

    @classmethod
    def get_decryption_manager(cls):
        return DecryptionManager(cls.get_master_key_manager())

    def save(self, *args, **kwargs):
        if self.pk is None:  # Only encrypt new records
            encryption_manager = self.get_encryption_manager()
            self.key = encryption_manager.encrypt(self.key)
        super().save(*args, **kwargs)

    @property
    def key(self):
        decryption_manager = self.get_decryption_manager()
        return decryption_manager.decrypt(self.key)

    @key.setter
    def key(self, value):
        encryption_manager = self.get_encryption_manager()
        self.key = encryption_manager.encrypt(value)
